BME280 ships at 0x76 by default; some boards strap it to 0x77. Wire defaults to SDA=8, SCL=9 on this DevKit per the board profile.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_BME280.h>

const uint8_t BME_ADDR = 0x76;
Adafruit_BME280 bme;

void setup() {
  Serial.begin(115200);
  Wire.begin(8, 9);
  if (!bme.begin(BME_ADDR, &Wire)) {
    Serial.println("BME280 not found at 0x76");
    while (true) { delay(1000); }
  }
}

void loop() {
  Serial.printf("T=%.2fC  P=%.1fhPa  H=%.1f%%\n",
                bme.readTemperature(),
                bme.readPressure() / 100.0f,
                bme.readHumidity());
  delay(1000);
}
```

BSEC2 needs the Bosch closed-source library plus its license blob. The simpler Adafruit_BME680 driver gives raw gas resistance instead of IAQ; if the user wants real IAQ they have to use BSEC2. Showing the BSEC2 path here.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <bsec2.h>

Bsec2 envSensor;

const bsecSensor sensorList[] = {
  BSEC_OUTPUT_IAQ,
  BSEC_OUTPUT_RAW_TEMPERATURE,
  BSEC_OUTPUT_RAW_HUMIDITY,
};

void newDataCallback(const bme68xData /*data*/, const bsecOutputs outputs, Bsec2 /*bsec*/) {
  for (uint8_t i = 0; i < outputs.nOutputs; i++) {
    const bsecData o = outputs.output[i];
    switch (o.sensor_id) {
      case BSEC_OUTPUT_IAQ:             Serial.printf("IAQ=%.0f acc=%d ", o.signal, o.accuracy); break;
      case BSEC_OUTPUT_RAW_TEMPERATURE: Serial.printf("T=%.2fC ",         o.signal); break;
      case BSEC_OUTPUT_RAW_HUMIDITY:    Serial.printf("H=%.1f%%\n",       o.signal); break;
    }
  }
}

void setup() {
  Serial.begin(115200);
  Wire.setSDA(4); Wire.setSCL(5); Wire.begin();
  envSensor.begin(BME68X_I2C_ADDR_HIGH, Wire);
  envSensor.updateSubscription(sensorList, 3, BSEC_SAMPLE_RATE_LP);
  envSensor.attachCallback(newDataCallback);
}

void loop() {
  envSensor.run();
}
```

STEMMA QT is on Wire (SDA=3, SCL=4). Power-gate GPIO7 has to be HIGH to enable the QT bus on this Feather.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_GFX.h>
#include <Adafruit_SSD1306.h>

const int I2C_PWR = 7;
const uint8_t OLED_ADDR = 0x3C;

Adafruit_SSD1306 display(128, 64, &Wire);

void setup() {
  pinMode(I2C_PWR, OUTPUT);
  digitalWrite(I2C_PWR, HIGH);
  Wire.begin(3, 4);
  if (!display.begin(SSD1306_SWITCHCAPVCC, OLED_ADDR)) {
    while (true) { delay(1000); }
  }
  display.clearDisplay();
  display.setTextSize(2);
  display.setTextColor(SSD1306_WHITE);
  display.setCursor(0, 24);
  display.println("ready");
  display.display();
}

void loop() {}
```

Tilt-from-accel is fine when stationary; under motion you'd fuse with the gyro. Keeping this simple per the request.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_MPU6050.h>

Adafruit_MPU6050 mpu;

void setup() {
  Serial.begin(115200);
  Wire.setSDA(4); Wire.setSCL(5); Wire.begin();
  if (!mpu.begin()) {
    Serial.println("MPU6050 not found");
    while (true) { delay(1000); }
  }
}

void loop() {
  sensors_event_t a, g, t;
  mpu.getEvent(&a, &g, &t);
  float pitch = atan2f(a.acceleration.x, sqrtf(a.acceleration.y * a.acceleration.y + a.acceleration.z * a.acceleration.z)) * 180.0f / PI;
  float roll  = atan2f(a.acceleration.y, a.acceleration.z) * 180.0f / PI;
  Serial.printf("pitch=%.1f roll=%.1f\n", pitch, roll);
  delay(50);
}
```

The Sense has SHT30 wired to the default Wire bus at 0x44.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_SHT31.h>

Adafruit_SHT31 sht30;

void setup() {
  Serial.begin(115200);
  Wire.begin();
  if (!sht30.begin(0x44)) {
    Serial.println("SHT30 not found at 0x44");
    while (true) { delay(1000); }
  }
}

void loop() {
  float t = sht30.readTemperature();
  float h = sht30.readHumidity();
  if (!isnan(t) && !isnan(h)) {
    Serial.printf("T=%.2fC  H=%.1f%%\n", t, h);
  }
  delay(1000);
}
```

Standard 7-bit scan from 1 to 0x7F. Useful for confirming wiring before reaching for a driver.

```cpp
#include <Arduino.h>
#include <Wire.h>

void setup() {
  Serial.begin(115200);
  Wire.begin(8, 9);
  delay(100);

  Serial.println("I2C scan:");
  uint8_t found = 0;
  for (uint8_t addr = 1; addr < 0x7F; addr++) {
    Wire.beginTransmission(addr);
    if (Wire.endTransmission() == 0) {
      Serial.printf("  0x%02X\n", addr);
      found++;
    }
  }
  Serial.printf("%u devices\n", found);
}

void loop() {}
```

SHT41 sits on the same 0x44 address as SHT3x, but the Sensirion driver targets it directly.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <SensirionI2cSht4x.h>

SensirionI2cSht4x sht;

void setup() {
  Serial.begin(115200);
  Wire.begin(6, 7);
  sht.begin(Wire, SHT40_I2C_ADDR_44);
  sht.softReset();
  delay(10);
}

void loop() {
  float t, rh;
  if (sht.measureLowestPrecision(t, rh) == 0) {
    Serial.printf("T=%.2fC  RH=%.1f%%\n", t, rh);
  } else {
    Serial.println("sht41 read failed");
  }
  delay(2000);
}
```

SH1106 looks like an SSD1306 but has a 132-pixel framebuffer with a 2-pixel offset, so the SH1106-aware driver matters.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_GFX.h>
#include <Adafruit_SH110X.h>

const uint8_t OLED_ADDR = 0x3C;
Adafruit_SH1106G display(128, 64, &Wire);
uint32_t counter = 0;
uint32_t lastTick = 0;

void setup() {
  Wire.setSDA(4); Wire.setSCL(5); Wire.begin();
  display.begin(OLED_ADDR, true);
  display.setTextSize(3);
  display.setTextColor(SH110X_WHITE);
}

void loop() {
  if (millis() - lastTick >= 1000) {
    lastTick = millis();
    display.clearDisplay();
    display.setCursor(0, 16);
    display.printf("%lu", counter++);
    display.display();
  }
}
```

BMP280 is at 0x77, APDS9960 is at 0x39 on the Sense's internal I2C bus.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_BMP280.h>
#include <Adafruit_APDS9960.h>

Adafruit_BMP280 bmp;
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(115200);
  Wire.begin();
  if (!bmp.begin(0x77)) { Serial.println("BMP280 fail"); while (true) delay(1000); }
  if (!apds.begin())    { Serial.println("APDS fail");   while (true) delay(1000); }
  apds.enableColor(true);
  apds.enableProximity(true);
}

void loop() {
  float p = bmp.readPressure() / 100.0f;
  uint16_t r, g, b, c;
  while (!apds.colorDataReady()) delay(5);
  apds.getColorData(&r, &g, &b, &c);
  uint8_t prox = apds.readProximity();
  Serial.printf("p=%.1fhPa  lux=%u  prox=%u\n", p, c, prox);
  delay(1000);
}
```

Hysteresis (0.25 C band) prevents jitter at the threshold.

```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_BME280.h>

const uint8_t BME_ADDR = 0x76;
const float THRESHOLD_C = 25.0f;
const float HYSTERESIS_C = 0.25f;

Adafruit_BME280 bme;
bool aboveThreshold = false;

void setup() {
  Serial.begin(115200);
  Wire.begin();
  if (!bme.begin(BME_ADDR)) { Serial.println("BME fail"); while (true) delay(1000); }
  aboveThreshold = bme.readTemperature() > THRESHOLD_C;
}

void loop() {
  float t = bme.readTemperature();
  if (aboveThreshold && t < THRESHOLD_C - HYSTERESIS_C) {
    aboveThreshold = false;
    Serial.printf("FELL below %.2fC at T=%.2fC\n", THRESHOLD_C, t);
  } else if (!aboveThreshold && t > THRESHOLD_C + HYSTERESIS_C) {
    aboveThreshold = true;
    Serial.printf("ROSE above %.2fC at T=%.2fC\n", THRESHOLD_C, t);
  }
  delay(500);
}
```
